import Split from 'split.js'

export default function({ el, sizes = [20, 80], minSize = 350, gutterSize = 3 }) {
  const split = Split(el, {
    sizes,
    minSize,
    expandToMin: true,
    gutterSize,
    onDrag() {},
    onDragEnd(value) {
      if (!value.filter(c => isNaN(+c)).length) {
        value = value.map(c => +c)
      } else {
        value = [20, 80]
      }
    }
  })
  split.setSizes(sizes)
  return split
}
