const Util = {
  guid() {
    function s4() {
      return Math.floor((1 + Math.random()) * 0x10000)
        .toString(16)
        .substring(1)
    }
    return [s4() + s4(), s4(), s4(), s4(), s4(), s4() + s4()].join('-')
  },
  cookies: {
    get(key) {
      const c = document.cookie.split(';')
      const cookies = {}
      c.forEach(v => {
        const c_ = v.trim().split('=')
        if (c_.length >= 2) {
          cookies[c_[0]] = c_.slice(1).join('=')
        }
      })
      if (typeof key === 'undefined') {
        return cookies
      }
      else if (typeof cookies[key] === 'undefined') {
        return undefined
      }
      else {
        try {
          return decodeURIComponent(cookies[key])
        } catch {
          return cookies[key]
        }
      }
    },
    del(key) {
      Util.cookies.set({ key, val: '', days: -1 })
    },
    set(opt) {
      if (typeof opt !== 'undefined') {
        if (typeof opt.days === 'undefined') {
          opt.days = 15
        }
        let expires = ''
        const exdate = new Date()
        exdate.setDate(exdate.getDate() + opt.days)
        expires = `expires=${exdate.toUTCString()};`

        let domain = ''
        if (typeof opt.domain !== 'undefined') {
          domain = `domain=${opt.domain};`
        }

        let SameSite = 'SameSite=Lax;'
        if (typeof opt.SameSite !== 'undefined') {
          SameSite = `SameSite=${opt.SameSite};`
        }
        document.cookie = `${opt.key}=${encodeURIComponent(opt.val)};${SameSite}path=/;${expires};${domain}`
      }
    }
  },
  formatLang(lang = '') {
    let result = lang?.toLowerCase()
    switch (result) {
      case 'cn':
      case 'zh_cn':
      case 'zh-cn':
        result = 'cn'
        break
      case 'en':
      case 'en_us':
      case 'en-us':
        result = 'en'
        break
      case 'tw':
      case 'zh_tw':
      case 'zh-tw':
        result = 'tw'
        break
      case 'ja':
      default:
        break
    }
    return result
  }
}

export default Util
