<template>
  <div class="components-scheduler">
    <!-- header-months -->
    <ul class="header-months">
      <li v-for="(v, i) in dates" :key="`header-months_${i}`" :title="`${v.year}/${v.month}`">
        <div :class="[{'active': v.active}, v.cols?`colspan-${v.cols}`:'']">
          {{ getLocaleTitle(v.date) }}
        </div>
      </li>
    </ul>
    <b-overlay spinner-variant="primary" :show="loading" :class="`view-${viewCount}`">
      <b-form-row class="scheduler-header stuck">
        <b-col cols="12">
          <!-- months -->
          <ul class="months">
            <li v-for="(v, i) in dates" :key="`months_${i}`" :title="`${v.year}/${v.month}`">
              <div :class="['scheduler-header-label', {'active': v.active}, v.cols?`colspan-${v.cols}`:'']">
                {{ v.year }}/{{ v.month }}
              </div>
            </li>
          </ul>
        </b-col>
        <b-col cols="12">
          <!-- dates -->
          <ul class="dates">
            <li
              v-for="(v, i) in dates"
              :id="`dates_${i}`"
              :key="`dates_${i}`"
              boundary="document"
              :class="[
                'nowrap',
                'cursor-pointer',
                {
                  'today': isToday(v.date),
                  'holiday': isHoliday(v.date),
                  'weekend': isWeekend(v.date)
                }
              ]"
              @click="dateClickHandler(v.date, $event)"
            >
              <div class="px-1">
                <span>{{ v.week }} {{ v.day }}</span>
                <small v-if="getAllStockFull(v.date)" class="wb-icon">
                  {{ i18n('whole_building') }}
                </small>
              </div>

              <b-tooltip
                :target="`dates_${i}`"
                custom-class="b-tooltip-class"
                placement="top"
                triggers="hover"
                boundary="document"
              >
                {{ dateTooltip(v.date) }}
              </b-tooltip>
            </li>
          </ul>
        </b-col>
      </b-form-row>
      <!-- content -->
      <template v-for="(v, i) in resourceList">
        <!-- 庫存 -->
        <b-form-row :key="`contents_${i}`" class="contents-row stock">
          <b-col cols="12" :class="cname">
            <ul class="contents stock">
              <li
                v-for="(v2, i2) in dates"
                :key="`contents_${i}_${i2}`"
                :class="{
                  'full': getStock(v2.date, v.id).full,
                  'stock-notset': !checkStock(v2.date, v.id)
                }"
              >
                <div @click="stockClickHandler({ date: v2.date, room: v.id }, $event)">
                  <template v-if="hasSlot('slot-item-stock')">
                    <slot name="slot-item-stock" :scope="getStock(v2.date, v.id)"></slot>
                  </template>
                  <template v-else>
                    <small v-if="checkLock(v2.date, v.id)" class="lock-icon">
                      <i class="fa-solid fa-lock"></i>
                    </small>
                    <span v-if="checkStock(v2.date, v.id)">
                      {{ getStock(v2.date, v.id).stock }}
                    </span>
                    <small v-else>
                      {{ i18n('stock_notset') }}
                    </small>
                  </template>
                </div>
              </li>
            </ul>
          </b-col>
        </b-form-row>

        <!-- 待排房 -->
        <b-form-row v-if="showWait" :key="`contents_wait_${i}`" :class="['contents-row collapse-wait', {'active': isAllActive(v)}]">
          <b-col cols="12" :class="[cname, 'rowspan-1', `rowspan-${parseLayoutInfo(v, 'wait')}`]">
            <ul class="contents wait">
              <li
                v-for="(v2, i2) in dates"
                :key="`contents_wait_${i}_${i2}`"
                :class="{'full': getStock(v2.date, v.id).full}"
              >
                <div
                  data-type="wait"
                  droppable="true"
                  :data-date="v2.date"
                  :data-id="[v.id,'wait'].join()"
                  @dragenter="dragEnterHandler"
                  @dragleave="dragLeaveHandler"
                  @dragover="dragOverHandler"
                  @dragend="dragEndHandler"
                  @drop="dropHandler"
                  @click.self="itemClickHandler({
                    date: v2.date,
                    room: v.id,
                    num: 'wait',
                    full: getStock(v2.date, v.id).full
                  })"
                  @mousedown="mousedownHandler"
                >
                  <template v-for="(v3, i3) in waitDataResult([v2.date,v.id,''].join())">
                    <order-item
                      :key="`order-item_${i3}`"
                      :class="`item-order-${v3.order}`"
                      :data="v3"
                      :continuous="allowContinuous"
                      @dragstart="dragStartHandler"
                      @click="orderClickHandler"
                      @assign="assignClickHandler"
                    >
                      <template v-if="hasSlot('slot-item-info')" #slot-item-info="{ scope }">
                        <slot name="slot-item-info" :scope="scope"></slot>
                      </template>
                    </order-item>
                  </template>
                </div>
              </li>
            </ul>
          </b-col>
        </b-form-row>

        <!-- 已排房 -->
        <b-form-row
          v-for="(v1, i1) in v.children"
          :key="`contents_${i}_${i1}`"
          :class="['contents-row collapse', {'active':isActive(v)}]"
        >
          <b-col cols="12" :class="cname">
            <ul class="contents">
              <li
                v-for="(v2, i2) in dates"
                :key="`contents_${i}_${i1}_${i2}`"
                :class="{'full': getStock(v2.date, v.id).full}"
              >
                <div
                  data-type="content"
                  :data-date="v2.date"
                  :data-id="[v.id,v1.id].join()"
                  :data-disabled="v1.disabled"
                  @dragenter="dragEnterHandler"
                  @dragleave="dragLeaveHandler"
                  @dragover="dragOverHandler"
                  @dragend="dragEndHandler"
                  @drop="dropHandler"
                  @click.self="itemClickHandler({
                    date: v2.date,
                    room: v.id,
                    num: v1.id,
                    full: getStock(v2.date, v.id).full
                  })"
                  @mousedown="mousedownHandler"
                >
                  <template v-for="(v3, i3) in dataResult[[v2.date,v.id,v1.id].join()] || []">
                    <order-item
                      :key="`order-item_${i3}`"
                      :data="v3"
                      :continuous="allowContinuous"
                      @dragstart="dragStartHandler"
                      @click="orderClickHandler"
                      @assign="assignClickHandler"
                    >
                      <template v-if="hasSlot('slot-item-info')" #slot-item-info="{ scope }">
                        <slot name="slot-item-info" :scope="scope"></slot>
                      </template>
                    </order-item>
                  </template>
                </div>
              </li>
            </ul>
          </b-col>
        </b-form-row>
      </template>
    </b-overlay>
  </div>
</template>

<script>
import $dayjs from 'dayjs'
import 'dayjs/locale/en'
import 'dayjs/locale/zh-tw'
import 'dayjs/locale/ja'

import $dict from '../modules/dict'
import $util from '../modules/util'
import orderItem from './item.vue'

export default {
  name: 'ComponentsScheduler',
  components: {
    orderItem
  },
  props: {
    today: {
      type: [Object, Number, String],
      default() {
        return Date.now()
      }
    },
    loading: {
      type: Boolean,
      default: false
    },
    showWait: {
      type: Boolean,
      default: true
    },
    locale: {
      type: String,
      default: 'en'
    },
    range: {
      type: Object,
      default() {
        return {
          // start: '2023-01-01', end: '2023-01-07'
        }
      }
    },
    resource: {
      type: Array,
      default() {
        return []
      }
    },
    stock: {
      type: Object,
      default() {
        return {}
      }
    },
    items: {
      type: Array,
      default() {
        return []
      }
    },
    holiday: {
      type: Array,
      default() {
        return [
          // {
          //   date: '2023-01-01',
          //   display_name: '元旦'
          // }
        ]
      }
    },
    format: {
      type: String,
      default: 'YYYY-MM-DD'
    },
    defaultHoliday: {
      type: Array,
      default() {
        return [6, 0]
      }
    },
    // 允許跨日
    // todo: 連續顯示移動時，因為都是移動第一個
    // 所以無法判斷使用者是要第一個移動第一個還是其他
    // 會造成沒有要"跨日"而跨日
    allowChangeDate: {
      type: Boolean,
      default: false
    },
    // 允許跨房型
    allowChangeType: {
      type: Boolean,
      default: false
    },
    //
    allowEdit: {
      type: Boolean,
      default: false
    },
    allowContinuous: {
      type: Boolean,
      default: false
    },
    allowAutoAssign: {
      type: Boolean,
      default: false
    },
    marginTop: {
      type: Number,
      default: 0
    }
  },
  data() {
    return {
      cname: 'resource-item',
      grouping: {},
      mousePosition: 0,
      currentChildId: {}
    }
  },
  computed: {
    dict() {
      return $dict[this.lang] || $dict.en
    },
    lang() {
      return $util.formatLang(this.locale)
    },
    now() {
      return $dayjs(this.today).format(this.format)
    },
    resourceList: {
      get() {
        return this.resource
      },
      set(value) {
        this.$emit('update:resource', value)
      }
    },
    itemList: {
      get() {
        const data = this.deepCopy(this.items)
        data.sort((a, b) => {
          if (a.start === b.start) return 0
          return a.start > b.start ? 1 : -1
        })
        return data
      },
      set(value) {
        this.$emit('update:items', value)
      }
    },
    viewCount() {
      const start = $dayjs(this.range.start)
      const end = $dayjs(this.range.end)
      const count = end.diff(start, 'days') + 1
      return count
    },
    dates() {
      const dates = [...new Array(this.viewCount)].fill({})
      const group = {}
      let prev = ''
      const result = dates.map((v, i) => {
        const obj = $dayjs(this.range.start).add(i, 'days')
        const date = obj.format(this.format)
        const holiday = this.holiday.find(c => c.date === date)
        const month = obj.format('MM')

        const active = prev !== month
        if (active) {
          prev = month
        }
        if (!group[month]) {
          group[month] = 0
        }
        group[month]++

        return {
          active,
          date,
          year: obj.format('YYYY'),
          month,
          day: obj.format('D'),
          week: obj.format('dd'),
          ...holiday ? { holiday: holiday.display_name } : {}
        }
      })

      result.forEach(v => {
        if (v.active) {
          v.cols = group[v.month]
        }
      })
      return result
    },
    dataResult() {
      // grouping
      const keys = {}
      const group = {}
      // if (this.allowContinuous) {
      this.itemList.forEach(v => {
        v.order_group = v.order_group || Math.random()

        if (!group[v.order_group]) {
          group[v.order_group] = {}
        }

        // check roomNumberId in child
        const currentRoomType = this.resourceList.find(c => c.id === v.room_type)
        if (currentRoomType && Array.isArray(currentRoomType.children) && currentRoomType.children.find(c => c.id === v.room_number_id)) {
          //
        }
        else {
          v.room_number_id = null
          // roomNumberId not in child
          if (!v.nan) {
            v.nan = 1
          }
        }

        // 分類用 _uid
        if (typeof v._uid === 'undefined') {
          v._uid = $util.guid()
        }

        const grouped = this.grouping[v._uid]
        let groupKey = [v.room_type, v.room_number_id, v.assign, grouped].join()
        const obj = group[v.order_group][groupKey]
        if (!obj) {
          group[v.order_group][groupKey] = []
        }
        else {
          const endDate = obj[obj.length - 1].end
          if (obj.length > 0 &&
              (obj[0].start === v.start || // 同日：待排房
              endDate !== v.start)) {
            if (!keys[groupKey]) {
              keys[groupKey] = groupKey + v.end
            }
            groupKey = keys[groupKey] || groupKey

            // groupKey += v.end
            if (!group[v.order_group][groupKey]) {
              group[v.order_group][groupKey] = []
            }
          }
        }
        group[v.order_group][groupKey].push(v)
      })
      // }

      // check overwrite
      const oData = this.deepCopy(this.itemList)
      const checkOver = this.checkOverwrite(oData)
      const checkOverFilter = []

      // data
      const result = {}
      this.itemList.forEach(v => {
        let roomNum = this.allowAutoAssign
          ? v.room_number_id
          : v.assign
            ? v.room_number_id
            : null

        // 重複指定同一個房間
        if (checkOver.length) {
          const key = [v.start, v.room_type, v.room_number_id].join()
          const over = checkOver.includes(key)
          if (over) {
            if (checkOverFilter.includes(key)) {
              roomNum = null
              v.room_number_id = null
              // v.title = `*${v.title}`
              // cell have multi child
              v.nan = 2
            }
            else {
              checkOverFilter.push(key)
            }
          }
        }

        const key = [v.start, v.room_type, roomNum].join()
        if (!result[key]) {
          result[key] = []
        }

        let _uids = []
        let items = []
        const index = Object.entries(group[v.order_group]).findIndex(([key, val]) => val.find(c => c._uid === v._uid))
        if (index !== -1) {
          _uids = Object.entries(group[v.order_group])[index][1].map(c => c._uid)
          items = Object.entries(group[v.order_group])[index][1].map(c => c.item_id)
        }
        result[key].push({
          ...v,
          _uids,
          items
        })
      })

      // sort
      const o = {}
      Object.entries(result).forEach(([key, val]) => {
        // items 多的排前面
        val.sort((a, b) => {
          const targetA = a._uids.join()
          const targetB = b._uids.join()
          switch (`${!!o[targetA]}${!!o[targetB]}`) {
            case 'truetrue':
              return 0
            case 'truefalse':
              return -1
            case 'falsetrue':
              return 1
            default:
              break
          }

          if (a._uids.length === b._uids.length) return 0
          return a._uids.length > b._uids.length ? -1 : 1
        })

        val.forEach((v, i) => {
          if (v._uids.length) {
            const target = v._uids.join()
            if (!o[target]) {
              o[target] = this.getMinOrder(val, o)
              //
              Object.entries(result).forEach(([key1, val1]) => {
                val1.forEach((v1, i1) => {
                  const target1 = v1._uids.join() || ''
                  if (target1 === target) {
                    v1.order = o[target]
                  }
                })
              })
            }
          }
        })
      })
      return result
    },
    dateOpenList() {
      const result = {}
      this.dates.forEach(v => {
        result[v] = this.getStock(v.date).full
      })
      return result
    }
  },
  watch: {
    items: {
      handler() {
        setTimeout(() => {
          this.updateRowspan()
        })
      },
      immediate: true,
      deep: true
    },
    allowAutoAssign: {
      handler() {
        setTimeout(() => {
          this.updateRowspan()
        })
      },
      immediate: false,
      deep: true
    },
    range: {
      handler() {
        this.resourceList.forEach(v => {
          delete v.layout
        })
        setTimeout(() => {
          this.updateRowspan()
        })
      },
      immediate: false,
      deep: true
    }
  },
  async mounted() {
    await this.$nextTick()

    setTimeout(() => {
      this.updateRowspan()
      this.scrollEventSet()
      window.scrollToToday()
    })
  },
  beforeDestroy() {
    if (this._scrollHandler) {
      window.removeEventListener('scroll', this._scrollHandler)
    }
    if (this._scrollOnceHandler) {
      window.removeEventListener('scroll', this._scrollOnceHandler)
    }
    if (this._horizontalScrollHandler) {
      const el = document.querySelector('.components-scheduler')
      if (el) el.removeEventListener('scroll', this._horizontalScrollHandler)
    }
    clearTimeout(this.debounceSettimeoutUpdateRowspan)
  },
  methods: {
    getLocaleTitle(value) {
      let result = ''
      switch ($dayjs.locale()) {
        case 'en':
          result = $dayjs(value).format(`MMMM YYYY`)
          break
        default:
          result = $dayjs(value).format(`YYYY${this.i18n('year')}MMM`)
          break
      }
      return result
    },
    hasSlot(name = 'default') {
      return !!this.$slots[name] || !!this.$scopedSlots[name]
    },
    isActive(v) {
      return typeof v.active !== 'undefined' ? v.active : true
    },
    isAllActive(v) {
      return this.isActive(v) && (typeof v.waitActive !== 'undefined' ? v.waitActive : true)
    },
    updateItemPosition() {
      const data = this.deepCopy(this.itemList)
      data.forEach(v => {
        const el = document.querySelector(`[data-_uid="${v._uid}"]`)
        if (el) {
          const { left, right } = el.getBoundingClientRect()
          v.left = left.toFixed(0)
          v.right = right.toFixed(0)
        }
      })
      this.itemList = data
    },
    mousedownHandler(e) {
      this.mousePosition = e.x
    },
    i18n(value) {
      return this.dict[value]
    },
    scrollEventSet() {
      const resource = document.querySelector('.components-resource .resource-header.stuck')
      const stuck = document.querySelector('.components-scheduler .scheduler-header.stuck')
      const stuck1 = document.querySelector('.header-months')
      if (resource && stuck) {
        this._scrollOnceHandler = () => {
          this.offsetY = stuck.getBoundingClientRect().top + 1 - this.marginTop
        }
        window.addEventListener('scroll', this._scrollOnceHandler, { once: true })

        this._scrollHandler = () => {
          const s = this.getScroll()
          const top = s.top - this.offsetY
          stuck.style.top = top > 0 ? `${top}px` : 0
          resource.style.top = stuck.style.top

          if (stuck1) {
            stuck1.style.top = stuck.style.top
          }
        }
        window.addEventListener('scroll', this._scrollHandler)
      }

      const schedulerEl = document.querySelector('.components-scheduler')
      if (schedulerEl) {
        this._horizontalScrollHandler = function() {
          const months = document.querySelector('.header-months')
          if (months) months.scrollLeft = this.scrollLeft
        }
        schedulerEl.addEventListener('scroll', this._horizontalScrollHandler)
      }
      this.updateMonthsBarStyle()
    },
    updateMonthsBarStyle() {
      const list = document.querySelectorAll('.header-months > li > div')
      document.querySelectorAll('.scheduler-header .months > li > .scheduler-header-label').forEach((v, i) => {
        const width = v.getBoundingClientRect().width
        list[i].style.setProperty('width', `${width}px`, 'important')

        const width1 = v.parentElement.getBoundingClientRect().width + 0.5
        list[i].parentElement.style.setProperty('width', `${width1}px`)
        list[i].parentElement.style.removeProperty('z-index')
        if ([...v.classList].includes('active')) {
          list[i].parentElement.style.zIndex = 1
        }
      })
    },
    getScroll() {
      const body = document.body
      const element = document.documentElement
      const top = parseFloat(window.pageYOffset || body.scrollTop || element.scrollTop)
      return {
        top,
        bottom: body.clientHeight - window.innerHeight - top
      }
    },
    getStock(date, id) {
      return this.stock[id]?.[date] || {}
    },
    checkStock(date, id) {
      const stock = this.getStock(date, id)
      return typeof stock.stock !== 'undefined'
    },
    checkLock(date, id) {
      const stock = this.getStock(date, id)
      return typeof stock.open === 'undefined' ? false : !stock.open
    },
    getAllStockFull(date) {
      let result = false
      Object.entries(this.stock).forEach(([key, val]) => {
        if (!result) {
          result = !!val[date]?.full
        }
      })
      return result
    },
    getMinOrder(val, o) {
      let min = 1
      if (val.length > 1) {
        const list = val.map(c => o[c._uids.join()]).filter(c => c)
        while (list.includes(min)) {
          min += 1
        }
      }
      return min
    },
    waitDataResult(value) {
      const data = this.dataResult[value] || []
      data.sort((a, b) => {
        if (a.order === b.order) return 0
        return a.order > b.order ? 1 : -1
      })
      return data
    },
    //
    deepCopy(value) {
      return JSON.parse(JSON.stringify(value))
    },
    isToday(value) {
      return value === this.now
    },
    isWeekend(value) {
      return this.defaultHoliday.includes($dayjs(value).day())
    },
    isHoliday(value) {
      const hday = this.holiday.find(c => c.date === value)
      return hday?.display_name || ''
    },
    //
    dateTooltip(value) {
      const result = [value]
      const isToday = this.isToday(value)
      const isHoliday = this.isHoliday(value)
      if (isToday) {
        result.push(`(${this.i18n('today')})`)
      }
      if (isHoliday) {
        result.push(`(${isHoliday})`)
      }
      return result.join('')
    },
    dateClickHandler(value, e) {
      this.$emit('click', {
        type: 'date',
        value,
        e
      })
    },
    stockClickHandler(value, e) {
      const { date, room, num } = value
      this.$emit('click', {
        type: 'stock',
        value,
        data: this.getStock(date, room),
        e
      })
    },
    orderClickHandler(value) {
      this.$emit('click', {
        type: 'order',
        value
      })
    },
    assignClickHandler(data) {
      const { value, e } = data
      this.$emit('assign', {
        type: 'assign',
        value,
        e
      })
    },
    itemClickHandler(value) {
      const { date, room, num, full } = value
      if (this.allowEdit && !full) {
        this.$emit('click', {
          type: 'item',
          value
        })
      }
    },
    // drag drop
    dragStartHandler(e) {
      // this.dragTarget = e.target
      this.currentChildId = e.target.parentNode.dataset
      const dataset = e.target?.dataset
      if (dataset?._uid) {
        const option = {
          ...this.currentChildId,
          _uid: dataset._uid,
          _uids: dataset._uids,
          rawData: e.rawData
        }
        this.dragTarget = option
        e.dataTransfer.setData('text/plain', JSON.stringify(option))
        e.dataTransfer.effectAllowed = 'move'
      }
      e.target.style.opacity = 0.5

      this.$emit('drop-start', e)
    },
    dragOverHandler(e) {
      document.querySelectorAll('.contents-row.border-primary').forEach(v => {
        v.classList.remove('border-primary')
      })

      document.body.style.cursor = ''
      const { type, id, date, disabled } = e.target.dataset

      if (id) {
        const target = document.querySelector(`[data-id="${id.split(',')[1]}"]`)
        if (target) {
          target.closest('.contents-row').classList.add('border-primary')
        }
      }

      if (disabled === 'true') {
        document.body.style.cursor = 'not-allowed'
        e.target.style.background = '#f2f2f2'
      }
      else {
        e.preventDefault()
        const count = e.target.querySelectorAll('.components-item').length
        if (id && (type === 'wait' || !count)) {
          e.target.style.background = '#f2f2f2'
        }

        // 處理允許跨日
        if (!this.allowChangeDate) {
          if (date !== this.currentChildId.date) {
            document.body.style.cursor = 'not-allowed'
          }
        }

        // 處理允許跨房型
        if (!this.allowChangeType) {
          try {
            const fromId = (id || '').split(',')[0]
            const toId = (this.currentChildId.id || '').split(',')[0]
            if (fromId !== toId) {
              document.body.style.cursor = 'not-allowed'
            }
          }
          catch (ex) {
            //
          }
        }
      }

      e.target.style.pointerEvents = ''
      if (type === 'item') {
        e.target.style.pointerEvents = 'none'
      }

      this.$emit('drop-over', e)
    },
    dragLeaveHandler(e) {
      e.preventDefault()
      e.target.style.background = ''
      this.$emit('drop-leave', e)
    },
    dragEnterHandler(e) {
      e.preventDefault()
      this.$emit('drop-enter', e)
    },
    dragEndHandler(e) {
      e.preventDefault()
      this.clearDragStyle()
      this.$emit('drop-end', e)
    },
    dropHandler(e) {
      e.preventDefault()
      this.clearDragStyle(e)

      // 處理允許跨房型
      if (!this.allowChangeType) {
        try {
          const data = JSON.parse(e.dataTransfer.getData('text/plain'))
          const fromId = (data.id || '').split(',')[0]
          const toId = (e.target.dataset.id || '').split(',')[0]
          if (fromId !== toId) {
            this.updateRowspan()
            return
          }
        }
        catch (ex) {
          return
        }
      }

      const { type, id } = e.target.dataset
      if (id) {
        const count = e.target.querySelectorAll('.components-item').length
        const setAssign = type !== 'wait'
        try {
          const data = JSON.parse(e.dataTransfer.getData('text/plain'))
          const { _uid, _uids, rawData } = data
          const { date, id } = e.target.dataset
          const [room, num] = id.split(',').map(c => +c)

          if (type === 'wait' || !count || id === data.id) {
            const oData = this.deepCopy(this.itemList)
            if (this.allowContinuous) {
              const list = _uids.split(',')
              let dd = 0
              // 處理允許跨日
              if (this.allowChangeDate) {
                let itemIndex = -1
                let minDx = Number.MAX_SAFE_INTEGER
                list.forEach((v, i) => {
                  const index = oData.findIndex(c => c._uid === v)
                  const left = +oData[index].left
                  const dx = this.mousePosition - left
                  if (dx > 0 && dx < minDx) {
                    minDx = dx
                    itemIndex = i
                  }
                })
                const dataIndex = oData.findIndex(c => c._uid === list[itemIndex])
                dd = $dayjs(date).diff($dayjs(oData[dataIndex].start), 'days') // 計算跨日
              }
              else {
                if (date !== data.date) {
                  return
                }
              }
              list.forEach(v => {
                const index = oData.findIndex(c => c._uid === v)
                oData[index].assign = setAssign
                oData[index].room_type = room
                oData[index].room_number_id = num || null
                if (dd) {
                  oData[index].start = $dayjs(oData[index].start).add(dd, 'days').format(this.format)
                  oData[index].end = $dayjs(oData[index].end).add(dd, 'days').format(this.format)
                }
              })
            }
            else {
              const index = oData.findIndex(c => c._uid === _uid)
              oData[index].assign = setAssign
              oData[index].room_type = room
              oData[index].room_number_id = num || null
              const dd = $dayjs(date).diff($dayjs(oData[index].start), 'days')

              // 處理允許跨日
              if (!this.allowChangeDate) {
                try {
                  const aData = JSON.parse(e.dataTransfer.getData('text/plain'))
                  const aDate = e.target.dataset.date
                  if (aData.date && aData.date !== aDate) {
                    this.updateRowspan()
                    return
                  }
                }
                catch (ex) {
                  return
                }
              }

              if (dd) {
                oData[index].start = date
                oData[index].end = $dayjs(oData[index].end).add(dd, 'days').format(this.format)
              }
            }

            // check overwrite
            const checkOver = this.checkOverwrite(oData)
            if (!checkOver.length) {
              setTimeout(() => {
                this.itemList = oData

                this.$emit('drop', {
                  _uid,
                  date,
                  room,
                  ...num ? { num } : null,
                  rawData
                })
              })
            }
            else {
              const targetList = checkOver[0].split(',')
              const target = document.querySelector([
                '[data-type="content"]',
                `[data-date="${targetList[0]}"]`,
                `[data-id="${[targetList[1], targetList[2]].join()}"]`
              ].join(''))
              if (target) {
                target.classList.add('easeInAnim')
                setTimeout(() => {
                  target.classList.remove('easeInAnim')
                }, 500)
              }
              // e.target.classList.add('easeInAnim')
              // setTimeout(() => {
              //   e.target.classList.remove('easeInAnim')
              // }, 500)
            }
          }
        }
        catch (ex) {
          return
        }
      }

      // clear record grouping
      setTimeout(() => {
        this.grouping = {}
        this.updateRowspan()
      })
    },
    clearDragStyle() {
      this.currentChildId = {}
      document.body.style.cursor = ''
      document.querySelectorAll('.components-item').forEach(v => {
        v.style.pointerEvents = ''
        v.style.background = ''
        v.style.opacity = ''
      })
      document.querySelectorAll('.resource-item li > div[data-type]').forEach(v => {
        v.style.background = ''
      })
      document.querySelectorAll('.contents-row.border-primary').forEach(v => {
        v.classList.remove('border-primary')
      })
    },
    updateRowspan() {
      if (this.debounceSettimeoutUpdateRowspan) {
        return
      }
      clearTimeout(this.debounceSettimeoutUpdateRowspan)
      this.debounceSettimeoutUpdateRowspan = setTimeout(() => {
        delete this.debounceSettimeoutUpdateRowspan
      }, 100)

      const list = this.deepCopy(this.resourceList)
      // 清除 layout rowspan 記錄，後面會重算
      list.forEach((v, i) => {
        delete list[i].layout
      })

      const waitRowspan = []
      const selector = [
        `.${this.cname} [data-type="wait"]`,
        `.${this.cname} [data-type="content"]`
      ].join()
      document.querySelectorAll(selector).forEach(v => {
        const rowspan = v.querySelectorAll('.components-item').length
        const id = v.dataset.id
        const resId = id.split(',')[0]
        const itemId = id.split(',')[1]
        const index = list.findIndex(c => c.id === +resId)
        if (index !== -1) {
          const obj = list[index]
          if (!obj.layout) {
            obj.layout = {}
          }
          if (!obj.layout[itemId]) {
            obj.layout[itemId] = {
              rowspan: 0
            }
          }
          if (itemId === 'wait') {
            if (!waitRowspan[resId]) {
              waitRowspan[resId] = 0
            }
            waitRowspan[resId] += rowspan
            obj.layout[itemId].waitRowspan = waitRowspan[resId]
          }
          obj.layout[itemId].rowspan = Math.max(obj.layout[itemId].rowspan, rowspan)

          if (this.allowAutoAssign) {
            obj.waitActive = true
          }
          list[index] = obj
        }
      })
      this.resourceList = list

      setTimeout(() => {
        this.clearDragStyle()
        this.updateItemPosition()
        this.updateMonthsBarStyle()
      })
    },
    checkOverwrite(data) {
      // 計算所有格子中是否有超過一個項目的
      const oDataCheck = this.deepCopy(data)
      const group = {}
      if (!this.allowAutoAssign) {
        oDataCheck.forEach(v => {
          if (!v.assign) {
            v.room_number_id = null
          }
        })
      }
      oDataCheck
        .filter(c => c.room_number_id)
        // .map(c => [c.start, c.room_type, c.room_number_id].join())
        .forEach(v => {
          const key = [v.start, v.room_type, v.room_number_id].join()
          if (!group[key]) {
            group[key] = []
          }
          group[key].push(v)
        })

      // 若有任一超過一個項目
      return [...new Set(Object.entries(group)
        .map(c => c[1])
        .filter(c => c.length > 1)
        .flat()
        .map(c => [c.start, c.room_type, c.room_number_id].join()))
      ]
      // return Object.entries(group).map(c => c[1]).find(c => c.length > 1)
    },
    parseLayoutInfo(data, value) {
      return data?.layout?.[value]?.rowspan || 1
    }
  }
}
</script>

