<template>
  <div class="component-switch-button">
    <b-overlay :show="loading" spinner-small spinner-variant="primary" class="d-inline-block w-100">
      <b-form-checkbox v-model="result" switch :size="size">
        <template #default>
          <slot></slot>
        </template>
      </b-form-checkbox>
    </b-overlay>
  </div>
</template>

<script>
export default {
  name: 'ComponentSwitchButton',
  props: {
    value: {
      type: [Boolean, Number],
      default: false
    },
    size: {
      type: String,
      default: 'lg' // sm|md|lg
    },
    loading: {
      type: Boolean,
      default: false
    }
  },
  computed: {
    isNumber() {
      return typeof this.value === 'number'
    },
    result: {
      get() {
        return !!this.value
      },
      set(value) {
        this.$emit('input', this.isNumber
          ? value ? 1 : 0
          : !!value)
      }
    }
  }
}
</script>

