<template>
  <div
    :id="data._uid"
    v-b-tooltip.hover
    :title="data.tooltip"
    class="components-item"
    data-type="item"
    :data-_uid="data._uid"
    :data-_uids="data._uids"
    draggable="true"
    :class="[
      data.checked_status,
      {
        'assign': data.assign,
        'unassign': !data.assign,
        continuous
      },
      colSpan
    ]"
    :data-order="data.order"
    @dragstart="dragStartHandler"
    @click="clickHandler"
  >
    <b-overlay spinner-variant="primary" :show="loading">
      <template v-if="hasSlot('slot-item-info')">
        <slot name="slot-item-info" :scope="data"></slot>
      </template>
      <template v-else>
        {{ data.title }},
        {{ data.start }}-{{ data.end }},
        {{ data.assign }}
      </template>

      <div class="assign-button" @click="assignClickHandler">
        <i class="fas fa-chevron-circle-right"></i>
      </div>
    </b-overlay>
  </div>
</template>

<script>
export default {
  name: 'ComponentsItem',
  props: {
    loading: {
      type: Boolean,
      default: false
    },
    data: {
      type: Object,
      default() {
        return {}
      }
    },
    continuous: {
      type: Boolean,
      default: false
    }
  },
  data() {
    return {
    }
  },
  computed: {
    colSpan() {
      let result = null
      if (this.continuous && this.data._uids.length > 1) {
        const index = this.data._uids.indexOf(this.data._uid)
        // const opacity = index !== 0 ? 'opacity-0' : ''
        result = [
          `colspan-${this.data._uids.length - index}`
          // opacity
        ].join(' ')
      }
      return result
    }
  },
  methods: {
    dragStartHandler(e) {
      e.rawData = this.data
      this.$emit('dragstart', e)
    },
    hasSlot(name = 'default') {
      return !!this.$slots[name] || !!this.$scopedSlots[name]
    },
    clickHandler() {
      this.$emit('click', this.data)
    },
    assignClickHandler(e) {
      e.stopPropagation()
      this.$emit('assign', {
        value: this.data,
        e
      })
    }
  }
}
</script>

